/**
 * Return the requested url from data object
 *
 * @param      {string}  url     The url
 * @param      {obj}     params  The parameters
 *
 * @return     {string}          Concatenated url
 */

export function uuid () {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    let r = Math.random() * 16 | 0; let v = c === 'x' ? r : (r & 0x3 | 0x8)
    return v.toString(16)
  })
}

export function concatenateUrl (url, params) {
  if (url === undefined) {
    throw new Error('No url param')
  }

  let result = url + '?'

  Object.keys(params).forEach((el, index) => {
    if (index === 0) {
      result += el + '=' + params[el]
    } else {
      result += '&' + el + '=' + params[el]
    }
  })

  return result
}

export async function requestJson (url) {
  let headers = new Headers()
  headers.append('pragma', 'no-cache')
  headers.append('cache-control', 'no-cache')
  const response = await fetch(url, { cache: 'no-cache', headers: headers })
  const json = await response.json()
  return json
}

export async function requestAgreement () {
  const response = await fetch('config/agreement.html')
  const text = await response.text()
  return text
}

export function ibsData (b, c, d, e, f) { // b - пол (1 - женщина, 0 - мужчина), с - возраст, d - давление, e - курение (1 - да), f - холестерин
  b = Number(String(b).replace(',', '.'))
  c = Number(String(c).replace(',', '.'))
  d = Number(String(d).replace(',', '.'))
  e = Number(String(e).replace(',', '.'))
  f = Number(String(f).replace(',', '.'))
  let g = null
  let h = null
  if (c < 20) c = 20
  if (b === 0) {
    g = -21
    h = 4.62
  } else {
    g = -28.7
    h = 6.23
  }
  let l = Math.exp(-Math.exp(g) * Math.pow(c - 20, h))
  let p = Math.exp(-Math.exp(g) * Math.pow(c - 10, h))
  // eslint-disable-next-line no-unused-expressions
  b === 0 ? (g = -25.7, h = 5.47) : (g = -30, h = 6.42)
  b = Math.exp(-Math.exp(g) * Math.pow(c - 20, h))
  c = Math.exp(-Math.exp(g) * Math.pow(c - 10, h))
  g = 0.24 * (f - 6) + 0.018 * (d - 120) + 0.71 * e
  d = 0.02 * (f - 6) + 0.022 * (d - 120) + 0.63 * e
  return 100 * (1 - Math.pow(p, Math.exp(g)) / Math.pow(l, Math.exp(g)) + (1 - Math.pow(c, Math.exp(d)) / Math.pow(b, Math.exp(d))))
}

export function getMedResult (data) {
  // console.log(data)
  let imt = Math.round(data.weight / (data.growth * data.growth / (100 * 100)))
  let ibs = ibsData(data.gender, data.age, data.artPressure, data.smoke, data.cholesterol)
  if (typeof data.heartProblems === 'undefined') data.heartProblems = 0
  if (data.heartProblems === 0) { // Без заболеваний сердца
    if (data.gender === 1) { // женщины
      if (data.age <= 40) {
        // console.log('ж 40')
        if (data.artPressure >= 140 || data.cholesterol >= 7) return 5
        if (data.relativesProblems === 1) return 4
        if (data.imt >= 30) return 3
        if (data.smoke === 1) return 2
      } else if (data.age <= 75) {
        // console.log('ж 75')
        if (ibs >= 5) return 10
        if (ibs >= 1) {
          if (imt < 30 && data.cholesterol < 7 && data.relativesProblems === 0) return 8
          if (imt >= 30 || data.cholesterol >= 7 || data.relativesProblems === 1) return 9
        }
        if (ibs < 1) {
          if (imt < 30 && data.cholesterol < 7 && data.relativesProblems === 0) return 6
          if (imt >= 30 || data.cholesterol >= 7 || data.relativesProblems === 1) return 7
        }
      } else {
        return 11
      }
    } else { // мужчины
      if (data.age <= 40) {
        // console.log('м 40')
        if (data.artPressure >= 140 || data.cholesterol >= 7) return 5
        if (data.relativesProblems === 1) return 4
        if (data.imt >= 30) return 3
        if (data.smoke === 1) return 2
      } else if (data.age <= 75) {
        // console.log('м 75')
        if (ibs >= 5) return 10
        if (ibs >= 1) {
          if (imt < 30 && data.cholesterol < 7 && data.relativesProblems === 0) return 8
          if (imt >= 30 || data.cholesterol >= 7 || data.relativesProblems === 1) return 9
        }
        if (ibs < 1) {
          if (imt < 30 && data.cholesterol < 7 && data.relativesProblems === 0) return 6
          if (imt >= 30 || data.cholesterol >= 7 || data.relativesProblems === 1) return 7
        }
      } else {
        return 11
      }
    }
  } else { // С заболеваниями сердца
    return 12
  }
  return 1
}

export function inArray (value, array) {
  for (let i = 0; i < array.length; i++) {
    if (value === array[i]) return true
  }
  return false
}

export function msToTime (duration) {
  let milliseconds = parseInt((duration % 1000) / 1)
  let seconds = parseInt((duration / 1000) % 60)
  let minutes = parseInt((duration / (1000 * 60)) % 60)
  let hours = parseInt((duration / (1000 * 60 * 60)) % 24)
  hours = (hours < 10) ? '0' + hours : hours
  minutes = (minutes < 10) ? '0' + minutes : minutes
  seconds = (seconds < 10) ? '0' + seconds : seconds
  return hours + ':' + minutes + ':' + seconds + '.' + milliseconds
}

export function getSpirigraphiaDataCompare (present, type) {
  if (type === 'FVC') {
    if (present < 50) return 3
    if (present < 70) return 2
    if (present < 85) return 1
    return 0
  }
  if (type === 'FEV1') {
    if (present < 35) return 3
    if (present < 55) return 2
    if (present < 75) return 1
    return 0
  }
  if (type === 'PEF') {
    if (present < 50) return 3
    if (present < 80) return 2
    if (present < 90) return 1
    return 0
  }
  if (type === 'FEV1/FVC') {
    if (present < 40) return 3
    if (present < 55) return 2
    if (present < 70) return 1
    return 0
  }
}

